div.script:
//

const searchButton = document.querySelector('.search__submit');
const searchInput = document.querySelector('.search__input');
const searchSelect = document.querySelector('.search__select');

let screeningTickets = document.querySelectorAll('.event-ticketmatic');
screeningTickets.forEach( ticket => {
    ticket.addEventListener('click', function(e){
        window.open( this.getAttribute('data-href'));
        e.preventDefault();
    })
})

    const activeFilters = {
        'program': null,
        'piano': null,
        'noPiano': null,
        'guest': null,
        'intro': null,
        'silent': null,
        'noSilent': null,
        'kids': null,
        'nl': null,
        'fr': null,
        'location': null,
        'startDate': null,
        'endDate': null,
        'month': null,
        'ledoux': null,
        'plateau': null
    }

    function populateMonthFilter(year, month, days){
        const selectElement = document.querySelector('.program-filter-element--month-days');
        selectElement.innerHTML = null;

        let optionElement = document.createElement('option');
        optionElement.innerHTML = '…';
        optionElement.value = '';
        selectElement.appendChild(optionElement);

        for( let i = 0; i < days; i++ ){
            let optionElement = document.createElement('option');
            let day = ( i < 9 ? '0' + (i + 1) : (i + 1) );
            optionElement.value = `${year}${month}${day}`;
            optionElement.innerHTML = day;
            selectElement.appendChild(optionElement);
        }
        selectElement.classList.remove('program-filter--hidden');
    }

    function removeMonthFilter(){
        document.querySelector('.program-filter-element--month-days').classList.add('program-filter--hidden');
    }

    let filterElements = document.querySelectorAll('.program-filter-element');
    for( let i = 0; i < filterElements.length; i++ ){
        let filterElement = filterElements[i];
        filterElement.addEventListener('change', function(){
            if( this.getAttribute('data-filter-type') == 'date' ){
                let selectedOption = this.querySelector(`option[value="${this.value}"]`);
                if( selectedOption.getAttribute('data-type') == 'day' ){
                    let filterDates = this.value.split('+');
                    activeFilters.startDate = filterDates[0];
                    activeFilters.endDate = (filterDates[1] ? filterDates[1] : filterDates[0]);
                    activeFilters.month = null;
                    removeMonthFilter();
                }else if( selectedOption.getAttribute('data-type') == 'month' ){
                    activeFilters.month = this.value;
                    populateMonthFilter( selectedOption.getAttribute('data-year'), selectedOption.value, parseInt(selectedOption.getAttribute('data-days')) );
                    activeFilters.startDate = null;
                    activeFilters.endDate = null;
                }else{
                    activeFilters.startDate = null;
                    activeFilters.endDate = null;
                    activeFilters.month = null;
                    removeMonthFilter();
                }
            }else if( this.getAttribute('data-filter-type') == 'month-days' ){
                if( this.value != '' ){
                    let filterDates = this.value.split('+');
                    activeFilters.startDate = filterDates[0];
                    activeFilters.endDate = (filterDates[1] ? filterDates[1] : filterDates[0]);
                }else{
                    activeFilters.startDate = null;
                    activeFilters.endDate = null;
                }

            }else{
                if( this.type == 'checkbox' ){
                    if( this.checked ){
                        activeFilters[this.getAttribute('data-filter-type')] = "1";
                    }else{
                        activeFilters[this.getAttribute('data-filter-type')] = null;
                    }
                }else if( this.value != '' ){
                    activeFilters[this.getAttribute('data-filter-type')] = this.value;
                }else{
                    activeFilters[this.getAttribute('data-filter-type')] = null;
                }
            }

            filterItems();
        });
    }

    searchInput.addEventListener('input', function(){ filterItems() });
    searchSelect.addEventListener('change', function(){ filterItems() });

    let screeningGroups = document.querySelectorAll('.screening-date-group');

    function scrollToTop(){
        document.querySelector('html').scrollIntoView();
    }

    function filterItems(){
        screeningGroups.forEach( screeningGroup => {
            let screeningsRemoved = 0;
            let screenings = screeningGroup.querySelectorAll('.screening');
            let removeCounterLimit = 1;

            screenings.forEach( screening => {
                let removeCounter = 0;
                Object.keys(activeFilters).forEach( key => {
                    if( activeFilters[key] != null ){
                        if( key == 'startDate' ){
                            if( screening.getAttribute(`data-date`) < activeFilters[key]){
                                removeCounter++;
                            }
                        }else if( key == 'endDate' ) {
                            if (screening.getAttribute(`data-date`) > activeFilters[key]) {
                                removeCounter++;
                            }
                        }else if( key === 'program' ) {
                            if( !screening.getAttribute(`data-${key}`) ){
                                removeCounter++;
                            }else if( !screening.getAttribute(`data-${key}`).split(',').includes(activeFilters[key]) ){
                                removeCounter++;
                            }
                        }else if( screening.getAttribute(`data-${key}`) != activeFilters[key]){
                            removeCounter++;
                        }
                    }
                } );

                const filterByType = (type) => {
                  if( screening.querySelectorAll(`.film__${type}`).length ){
                    if( !(screening.querySelector(`.film__${type}`).innerHTML.trim().toLowerCase().replace(' ', '&nbsp;').indexOf(searchInput.value.trim().replace(' ', '&nbsp;').toLowerCase()) > -1) ){
                      removeCounter++;
                    }
                  }else{
                    removeCounter++;
                  }
                }

                if( searchInput.value.length ){
                  if( searchSelect.value === "all" ){
                    const fields = ["titles", "directors", "cast"];
                    removeCounterLimit = 3;
                    fields.forEach(type => {
                      filterByType(type)
                    })
                  }else{
                    removeCounterLimit = 1;
                    filterByType(searchSelect.value)
                  }
                }
                if( removeCounter >= removeCounterLimit ){
                    screening.classList.add('screening--hidden');
                    screeningsRemoved++;
                }else{
                    screening.classList.remove('screening--hidden');
                }
            });

            if( screeningsRemoved == screenings.length ){
                screeningGroup.classList.add('screening-date-group--hidden');
            }else{
                screeningGroup.classList.remove('screening-date-group--hidden');
            }
        });
        scrollToTop();
    }

    const filterButtons = document.querySelectorAll('.run-filter');
    if( filterButtons.length ){
        for(let buttonIndex = 0; buttonIndex < filterButtons.length; buttonIndex++ ){
        filterButtons[buttonIndex].addEventListener('click', function(){
            filterItems();
        });
        }
    }

    function updateFilter( type, value ){
        if( typeof document.querySelector(`.program-filter-element[data-filter-type=${type}`) != "undefined" ){
            let filterElement = null;
            if( type == 'month' ){
                filterElement = document.querySelector(`.program-filter-element[data-filter-type=date]`);
            }else{
                filterElement = document.querySelector(`.program-filter-element[data-filter-type=${type}]`);
            }

            if( filterElement.type == 'checkbox' ){
                if( value == '1' ){
                    filterElement.checked = true;
                }else{
                     filterElement.checked = false;
                }
            }else if( filterElement.type == 'select' || filterElement.type == 'select-one' ){
                let filterOptions = filterElement.querySelectorAll('option');
                for( let i = 0; i < filterOptions.length; i++ ){
                    if( filterOptions[i].value == value ){
                        filterOptions[i].selected = true;
                        if( type == 'month' ){
                            populateMonthFilter(filterOptions[i].getAttribute('data-year'), value, filterOptions[i].getAttribute('data-days'));
                        }
                    }else{
                        filterOptions[i].selected = false;
                    }
                }
                filterElement.value = value;
            }
        }
    }

    const queryString = window.location.search;
    const urlParams = new URLSearchParams(queryString);
    const entries = urlParams.entries();

    let parameterCounter = 0;
    for(const entry of entries) {
        if( activeFilters[entry[0]] !== undefined || entry[0] == 'date' ){
            if( entry[0] == 'date' ){
                let filterDates = entry[1].split('-');
                activeFilters.startDate = filterDates[0];
                activeFilters.endDate = (filterDates[1] ? filterDates[1] : filterDates[0]);
            }else{
                if( entry[1] == "0" ){
                    activeFilters[entry[0]] = null;
                }else{
                    activeFilters[entry[0]] = entry[1];
                }

            }

            updateFilter( entry[0], entry[1] );
            parameterCounter++;
        }
    }

    if( parameterCounter ){
        console.log( activeFilters );
        filterItems();
    }

    document.addEventListener('DOMContentLoaded', function() {
        let yTarget = document.querySelector('[data-date="' + document.querySelector('#calendar').getAttribute('data-today') + '"]').offsetTop
        window.scrollTo({top: yTarget, behavior: 'smooth'});
    }, false);

//

//

    const searchScreenings = (term, types) => {
        showScreenings( findScreenings(term, types) );
    }
    const findScreenings = (term, types) => {
        let results = [];
        types.forEach( type => {
            const typeResults = dataset.filter( screening =>
                    screening[type].toLowerCase().indexOf(term.trim().toLowerCase()) > -1
                );
            results = [...results, ...typeResults];
        })
        return results;
    }

    const showScreenings = (results) => {
        document.querySelectorAll('.screening').forEach( screening => screening.classList.add('screening--hidden') );
        results.forEach( result => {
            let screeningToShow;
            document.querySelectorAll('.screening').forEach( screening => {
                if( screening.getAttribute('data-id') == result.id  ){
                    screeningToShow = screening;
                }

            });
            if( screeningToShow ){
                screeningToShow.style.display = 'block';
            }
        });
    }


    searchButton.addEventListener('click', (e) => {
        searchScreenings(searchInput.value, [searchSelect.value]);
    })

//

